      )}

      {/* Recent Activity List with Pagination */}
      {history.length > 0 && (
        <div>
            <div className="flex justify-between items-end mb-4 pl-2">
                <h3 className="text-lg md:text-xl font-serif text-white">{text.recentSessions}</h3>
