import React, { useState, useEffect, useCallback } from 'react';
import { UserProfile, AIAnalysis, AppView, Language } from './types';
import Header from './components/Header';
import Onboarding from './components/Onboarding';
import AudioRecorder from './components/AudioRecorder';
import FeedbackDisplay from './components/FeedbackDisplay';
import Dashboard from './components/Dashboard';
import Profile from './components/Profile';
import { analyzeAudio } from './services/geminiService';
import { supabase } from './services/supabaseClient';
import { translations } from './utils/translations';
import { checkAndEnforceVersion } from './utils/versionManager';

const UI_VERSION = '1.0.62'; 

const App: React.FC = () => {
  const [user, setUser] = useState<UserProfile | null>(null);
  const [userId, setUserId] = useState<string | null>(null);
  const [view, setView] = useState<AppView>(AppView.ONBOARDING);
  const [history, setHistory] = useState<AIAnalysis[]>([]);
  const [currentAnalysis, setCurrentAnalysis] = useState<AIAnalysis | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [isLoading, setIsLoading] = useState(true);
  const [showResetButton, setShowResetButton] = useState(false);

  const [isRecoveryMode, setIsRecoveryMode] = useState(false);
  const [language, setLanguage] = useState<Language>('zh');
  const text = translations[language];

  useEffect(() => {
    checkAndEnforceVersion();
    const resetTimer = setTimeout(() => {
        if (isLoading) setShowResetButton(true);
    }, 4000);

    const initApp = async () => {
        const timeoutPromise = new Promise((_, reject) => 
            setTimeout(() => reject(new Error("Initialization timed out")), 7000)
        );

        const sessionPromise = async () => {
            const { data, error } = await supabase.auth.getSession();
            if (error) throw error;
            if (data?.session) {
                await loadUserData(data.session.user.id, data.session.user.email || '');
            } else {
                setView(AppView.ONBOARDING);
            }
        };

        try {
            await Promise.race([sessionPromise(), timeoutPromise]);
        } catch (error) {
            if (!userId) setView(AppView.ONBOARDING);
        } finally {
            setIsLoading(false);
            clearTimeout(resetTimer);
        }
    };

    initApp();

    const { data: authListener } = supabase.auth.onAuthStateChange(async (event, session) => {
        if (event === 'PASSWORD_RECOVERY') {
            setIsRecoveryMode(true);
            setView(AppView.PROFILE); 
            setIsLoading(false);
        } else if (event === 'SIGNED_IN' && session) {
             if (!userId || userId !== session.user.id) {
                await loadUserData(session.user.id, session.user.email || '');
             }
        } else if (event === 'SIGNED_OUT') {
            setUser(null);
            setUserId(null);
            setHistory([]);
            setCurrentAnalysis(null);
            localStorage.removeItem('current_analysis');
            setView(AppView.ONBOARDING);
            setIsRecoveryMode(false);
            setIsLoading(false);
        }
    });

    return () => {
        authListener.subscription.unsubscribe();
        clearTimeout(resetTimer);
    };
  }, []);

  const calculateGamification = (historyList: AIAnalysis[]) => {
      let totalXP = 0;
      historyList.forEach(item => {
          const wordCount = item.transcript ? item.transcript.split(' ').length : 0;
          totalXP += Math.round((item.score || 0) + (wordCount * 0.5));
      });

      let level = 1;
      let costForNext = 300;
      let remainingXP = totalXP;
      while (remainingXP >= costForNext) {
          remainingXP -= costForNext;
          level++;
          costForNext += 500;
          if (costForNext > 3000) costForNext = 3000;
      }
      return { totalXP, level };
  };

  const loadUserData = async (uid: string, email: string) => {
    try {
      setUserId(uid);
      let profileBase = { name: 'Student', streak: 0, lastRecordingDate: null as string | null };
      const { data: profileData } = await supabase.from('profiles').select('*').eq('id', uid).single();
      if (profileData) {
        profileBase = {
            name: profileData.name,
            streak: profileData.streak || 0,
            lastRecordingDate: profileData.last_recording_date
        };
      } else {
          const { data: { user: authUser } } = await supabase.auth.getUser();
          profileBase.name = authUser?.user_metadata?.name || 'Student';
      }

      const { data: historyData } = await supabase.from('history').select('*').eq('user_id', uid).order('created_at', { ascending: true });

      let loadedHistory: AIAnalysis[] = [];
      if (historyData) {
        loadedHistory = historyData.map((h: any) => ({
          transcript: h.transcript,
          score: h.score || 0,
          grammarScore: h.grammar_score || 0,
          pronunciationScore: h.pronunciation_score || 0,
          fluencyScore: h.fluency_score || 0,
          vocabularyScore: h.vocabulary_score || 0,
          feedback: h.feedback || [], 
          tips: h.tips || [], 
          encouragement: h.encouragement,
          timestamp: h.created_at
        }));
        setHistory(loadedHistory);
      }

      const { totalXP, level } = calculateGamification(loadedHistory);
      setUser({
        name: profileBase.name,
        email: email,
        streak: profileBase.streak,
        lastRecordingDate: profileBase.lastRecordingDate,
        xp: totalXP,
        level: level
      });

      const savedAnalysisStr = localStorage.getItem('current_analysis');
      if (savedAnalysisStr) {
          try {
              const savedAnalysis = JSON.parse(savedAnalysisStr);
              setCurrentAnalysis(savedAnalysis);
              setView(AppView.ANALYSIS);
          } catch (e) {
              localStorage.removeItem('current_analysis');
              if (!isRecoveryMode) setView(AppView.DASHBOARD);
          }
      } else if (!isRecoveryMode) {
          setView(AppView.DASHBOARD);
      }
    } catch (e) {
      console.error("Error loading user data", e);
    } finally {
      setIsLoading(false);
    }
  };

  const handleAuth = async (email: string, password: string, name: string, mode: 'LOGIN' | 'SIGNUP') => {
    setIsLoading(true);
    try {
      if (mode === 'SIGNUP') {
        const { data, error } = await supabase.auth.signUp({ 
            email, password, options: { data: { name: name } }
        });
        if (error) throw error;
        if (data.user && !data.session) {
            alert("Registration successful! Check email to verify.");
            setIsLoading(false);
            return; 
        }
        if (data.user && data.session) {
          await supabase.from('profiles').insert({ id: data.user.id, email, name, streak: 0 });
          await loadUserData(data.user.id, email);
        }
      } else {
        const { data, error } = await supabase.auth.signInWithPassword({ email, password });
        if (error) throw error;
        if (data.user) await loadUserData(data.user.id, email);
      }
    } catch (error: any) {
      setIsLoading(false);
      throw error;
    }
  };

  const handleResetPassword = async (email: string) => {
      const { error } = await supabase.auth.resetPasswordForEmail(email, { redirectTo: window.location.origin });
      if (error) throw error;
  };

  const handleLogout = async () => {
    await supabase.auth.signOut();
    setUserId(null); setUser(null); setHistory([]); setCurrentAnalysis(null);
    localStorage.removeItem('current_analysis');
    setView(AppView.ONBOARDING);
  };

  const handleUpdateProfile = async (newName: string, currentPassword?: string, newPassword?: string) => {
    if (!user || !userId) return;
    try {
      await supabase.from('profiles').update({ name: newName }).eq('id', userId);
      if (newPassword) {
        if (!isRecoveryMode && currentPassword) {
            const { error } = await supabase.auth.signInWithPassword({ email: user.email, password: currentPassword });
            if (error) throw new Error("Incorrect current password.");
        }
        await supabase.auth.updateUser({ password: newPassword });
        if (isRecoveryMode) {
            setIsRecoveryMode(false);
            setView(AppView.DASHBOARD);
            return; 
        }
      }
      setUser({ ...user, name: newName });
    } catch (error: any) { throw error; }
  };

  const handleStartRecording = () => {
    setCurrentAnalysis(null);
    localStorage.removeItem('current_analysis');
    setView(AppView.RECORDING);
  };

  const handleAnalyze = useCallback(async (audioBase64: string, duration: number, mimeType: string) => {
    if (!user || !userId) return;
    setIsAnalyzing(true);
    try {
      const analysis = await analyzeAudio(audioBase64, duration, mimeType, language);
      const today = new Date().toDateString();
      const lastDate = user.lastRecordingDate ? new Date(user.lastRecordingDate).toDateString() : null;
      const isoTimestamp = new Date().toISOString();
      analysis.timestamp = isoTimestamp;
      let newStreak = (lastDate !== today) ? user.streak + 1 : user.streak;
      const newHistory = [...history, analysis];
      const { totalXP, level } = calculateGamification(newHistory);
      setUser({ ...user, streak: newStreak, lastRecordingDate: isoTimestamp, xp: totalXP, level: level });
      setCurrentAnalysis(analysis);
      setHistory(newHistory);
      localStorage.setItem('current_analysis', JSON.stringify(analysis));
      setView(AppView.ANALYSIS);
      setIsAnalyzing(false);
      (async () => {
          await supabase.from('history').insert({
            user_id: userId,
            transcript: analysis.transcript,
            score: analysis.score,
            grammar_score: analysis.grammarScore,
            pronunciation_score: analysis.pronunciationScore,
            fluency_score: analysis.fluencyScore,
            vocabulary_score: analysis.vocabularyScore,
            feedback: analysis.feedback || [], 
            tips: analysis.tips || [], 
            encouragement: analysis.encouragement,
            created_at: isoTimestamp
          });
          await supabase.from('profiles').upsert({ id: userId, streak: newStreak, last_recording_date: isoTimestamp });
      })();
    } catch (error: any) {
      setIsAnalyzing(false);
      throw error;
    }
  }, [user, userId, history, language]);

  const handleCloseFeedback = () => {
    setCurrentAnalysis(null);
    localStorage.removeItem('current_analysis');
    setView(AppView.DASHBOARD);
  };

  const handleViewHistory = (analysis: AIAnalysis) => {
    setCurrentAnalysis(analysis);
    localStorage.setItem('current_analysis', JSON.stringify(analysis));
    setView(AppView.ANALYSIS);
  };

  const handleManualReset = () => { localStorage.clear(); window.location.reload(); };

  if (isLoading) {
    return (
      <div className="min-h-screen bg-black flex flex-col items-center justify-center gap-6 p-4">
        <div className="text-blue-500 animate-pulse text-xl font-serif">Loading Global Voice Club...</div>
        {showResetButton && <button onClick={handleManualReset} className="px-4 py-2 bg-gray-800 border border-gray-600 rounded-lg text-white text-sm">Refresh & Fix</button>}
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-black text-white font-sans overflow-x-hidden w-full flex flex-col">
      <Header 
        user={user} text={text} language={language} version={UI_VERSION}
        onToggleLanguage={() => setLanguage(l => l === 'en' ? 'zh' : 'en')}
        onLogout={handleLogout} onProfileClick={() => setView(AppView.PROFILE)}
        onLogoClick={() => setView(AppView.DASHBOARD)}
      />
      <main className="w-full max-w-[95%] 2xl:max-w-[1800px] mx-auto px-4 md:px-8 pt-6 pb-12 flex-grow">
        {view === AppView.ONBOARDING && <Onboarding onAuth={handleAuth} onResetPassword={handleResetPassword} text={text} />}
        {view === AppView.DASHBOARD && user && <Dashboard user={user} history={history} onStartRecording={handleStartRecording} onViewHistory={handleViewHistory} text={text} />}
        {view === AppView.PROFILE && user && <Profile user={user} history={history} onUpdateProfile={handleUpdateProfile} onBack={() => setView(AppView.DASHBOARD)} text={text} isRecoveryMode={isRecoveryMode} />}
        {view === AppView.RECORDING && <AudioRecorder onAnalyze={handleAnalyze} isAnalyzing={isAnalyzing} onBack={() => setView(AppView.DASHBOARD)} text={text} />}
        {view === AppView.ANALYSIS && currentAnalysis && user && <FeedbackDisplay analysis={currentAnalysis} userName={user.name} userEmail={user.email} onClose={handleCloseFeedback} text={text} />}
      </main>
    </div>
  );
};

export default App;

import React, { useState, useMemo, useEffect } from 'react';
import { UserProfile, AIAnalysis, AppText, Language } from '../types';
import { XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, AreaChart, Area, ReferenceLine } from 'recharts';
import { actionPlan } from '../utils/translations';

interface DashboardProps {
  user: UserProfile;
  history: AIAnalysis[];
  onStartRecording: () => void;
  onViewHistory: (analysis: AIAnalysis) => void;
  text: AppText;
}

const Dashboard: React.FC<DashboardProps> = ({ user, history, onStartRecording, onViewHistory, text }) => {

  // Data slicing (Last 10 sessions)
  const recentHistory = history.slice(-10);

  const scoreData = recentHistory.map((h, i) => ({
    name: `S${i + 1}`,
    score: h.score || 0,
    date: new Date(h.timestamp).toLocaleDateString()
  })); 

  const metricsData = recentHistory.map((h, i) => ({
    name: `Session ${i + 1}`,
    grammar: h.grammarScore || 0,
    vocabulary: h.vocabularyScore || 0,
    pronunciation: h.pronunciationScore || 0,
  }));

  // --- Safe Average Calculations ---
  const averageScore = history.length > 0 
    ? Math.round(history.reduce((acc, curr) => acc + (curr.score || 0), 0) / history.length)
    : 0;

  const avgGrammar = history.length > 0
    ? Math.round(history.reduce((acc, curr) => acc + (curr.grammarScore || 0), 0) / history.length)
    : 0;

  const avgVocab = history.length > 0
    ? Math.round(history.reduce((acc, curr) => acc + (curr.vocabularyScore || 0), 0) / history.length)
    : 0;

  const avgPronunciation = history.length > 0
    ? Math.round(history.reduce((acc, curr) => acc + (curr.pronunciationScore || 0), 0) / history.length)
    : 0;

  const avgFluency = history.length > 0
    ? Math.round(history.reduce((acc, curr) => acc + (curr.fluencyScore || 0), 0) / history.length)
    : 0;

  const bestScore = history.length > 0 
    ? Math.max(...history.map(h => h.score || 0)) 
    : 0;

  const totalWordsSpoken = history.reduce((acc, curr) => {
    return acc + (curr.transcript ? curr.transcript.split(' ').length : 0);
  }, 0);

  // Analyze last session for strengths/weaknesses
  const lastSession = history.length > 0 ? history[history.length - 1] : null;
  let topStrength = "N/A";
  let focusArea = "N/A";

  if (lastSession) {
    const skills = [
        { name: text.grammar, val: lastSession.grammarScore || 0 },
        { name: text.pronunciation, val: lastSession.pronunciationScore || 0 },
        { name: text.vocabulary, val: lastSession.vocabularyScore || 0 },
        { name: text.fluency, val: lastSession.fluencyScore || 0 }
    ];
    skills.sort((a, b) => b.val - a.val);
    topStrength = skills[0].name;
    focusArea = skills[skills.length - 1].name;
  }

  // --- Enhanced Action Plan Logic ---
  const [isPlanExpanded, setIsPlanExpanded] = useState(false);
  const [completedTasks, setCompletedTasks] = useState<Record<string, boolean>>(() => {
    const saved = localStorage.getItem('completed_tasks');
    return saved ? JSON.parse(saved) : {};
  });

  useEffect(() => {
    localStorage.setItem('completed_tasks', JSON.stringify(completedTasks));
  }, [completedTasks]);

  const { suggestionObject, weakestSkill, nextMilestone, currentTierName, planId } = useMemo(() => {
    const foundationalAverages = [
        { id: 'grammar', val: avgGrammar, name: text.grammar },
        { id: 'vocabulary', val: avgVocab, name: text.vocabulary },
        { id: 'pronunciation', val: avgPronunciation, name: text.pronunciation }
    ];
    foundationalAverages.sort((a, b) => a.val - b.val);
    const weakest = foundationalAverages[0];

    let levelKey: 'beginner' | 'intermediate' | 'advanced' = 'beginner';
    let tierName = "Novice";
    if (averageScore >= 80) {
        levelKey = 'advanced'; tierName = "Maestro";
    } else if (averageScore >= 55) {
        levelKey = 'intermediate'; tierName = "Rising Star";
    }

    const pointsToNextRefresh = 3 - (averageScore % 3);
    const langKey = text.hello === "哈囉" ? 'zh' : 'en';
    const planTexts = (actionPlan as any)[langKey];
    const selectedAdvice = planTexts[weakest.id][levelKey];

    // Unique ID for the current plan to track its specific tasks
    const currentPlanId = `${weakest.id}_${levelKey}_${Math.floor(averageScore/3)}`;

    return { 
        suggestionObject: selectedAdvice, 
        weakestSkill: weakest, 
        nextMilestone: pointsToNextRefresh,
        currentTierName: tierName,
        planId: currentPlanId
    };
  }, [averageScore, avgGrammar, avgVocab, avgPronunciation, text.grammar, text.vocabulary, text.pronunciation, text.hello]);

  const toggleTask = (index: number) => {
    const key = `${planId}_${index}`;
    setCompletedTasks(prev => ({ ...prev, [key]: !prev[key] }));
  };

  const isAllCompleted = suggestionObject.tasks.every((_:any, i:number) => completedTasks[`${planId}_${i}`]);

  // --- XP / Level Logic ---
  let costForNext = 300;
  let remainingXP = user.xp;
  while (remainingXP >= costForNext) {
      remainingXP -= costForNext;
      costForNext += 500;
      if (costForNext > 3000) costForNext = 3000;
  }
  const progressPercentage = Math.min((remainingXP / costForNext) * 100, 100);

  // --- Pagination Logic ---
  const [currentPage, setCurrentPage] = useState(1);
  const itemsPerPage = 10;
  const reversedHistory = [...history].reverse();
  const totalPages = Math.ceil(reversedHistory.length / itemsPerPage);
  const currentHistoryItems = reversedHistory.slice((currentPage - 1) * itemsPerPage, currentPage * itemsPerPage);

  return (
    <div className="animate-fade-in space-y-8 md:space-y-10 pb-20 w-full">
      <div className="grid md:grid-cols-3 gap-6 md:gap-8 items-center bg-gradient-to-r from-gray-900 to-black p-5 md:p-8 rounded-3xl border border-gray-800 relative overflow-hidden">
         <div className="absolute top-0 right-0 w-64 h-64 bg-blue-600/10 rounded-full blur-3xl -mr-16 -mt-16 pointer-events-none"></div>
         <div className="md:col-span-2 relative z-10">
            <h2 className="text-3xl md:text-5xl font-serif text-white mb-4">{text.hello}, <span className="text-blue-500">{user.name}</span></h2>
            <div className="flex flex-wrap items-center gap-2 md:gap-4 mb-6">
                <div className="bg-gray-800 px-3 py-1 rounded-full text-xs md:text-sm border border-gray-700 whitespace-nowrap">🔥 <span className="font-bold text-white">{user.streak}</span> {text.streak}</div>
                <div className="bg-gray-800 px-3 py-1 rounded-full text-xs md:text-sm border border-gray-700 whitespace-nowrap">⚡ <span className="font-bold text-white">{user.xp}</span> {text.xp}</div>
            </div>
            <div className="mb-8 max-w-md w-full">
                <div className="flex justify-between text-xs uppercase text-gray-400 mb-1 tracking-wider"><span>{text.level} {user.level}</span><span>{text.nextLevel} {user.level + 1}</span></div>
                <div className="h-3 w-full bg-gray-800 rounded-full overflow-hidden"><div className="h-full bg-gradient-to-r from-blue-600 to-purple-500" style={{ width: `${progressPercentage}%` }}></div></div>
            </div>
            <div className="flex flex-col sm:flex-row items-center gap-4">
                <button onClick={onStartRecording} className="w-full md:w-auto bg-blue-600 hover:bg-blue-500 text-white px-6 py-4 md:px-8 rounded-full font-bold text-lg shadow-[0_0_20px_rgba(37,99,235,0.3)] transition-all transform hover:scale-105 flex items-center justify-center gap-3"><span className="bg-white/20 rounded-full p-1">🎙️</span> {text.startSession}</button>
                <a href="https://emphasized-nyala-97a.notion.site/Voice-AI-APP-2d1eb1df49ca8071b8bec4674dd89737?source=copy_link" target="_blank" rel="noopener noreferrer" className="text-gray-400 hover:text-white text-sm flex items-center gap-2 px-4 py-2 rounded-full border border-gray-800 hover:bg-gray-800 transition-all">{text.howToUse}</a>
            </div>
         </div>
         <div className="relative z-10 flex flex-col justify-center items-center md:items-end mt-4 md:mt-0">
             <div className="text-center"><div className="text-5xl md:text-6xl font-bold text-white mb-2">{averageScore}</div><div className="text-xs md:text-sm text-gray-400 uppercase tracking-widest">{text.avgScore}</div></div>
         </div>
      </div>

      {history.length > 0 && (
          <div className="grid grid-cols-2 md:grid-cols-4 gap-3 md:gap-4">
              <div className="bg-gray-900 p-4 md:p-6 rounded-2xl border border-gray-800 transition-colors"><div className="text-gray-500 text-[10px] md:text-xs uppercase tracking-wider mb-2">{text.bestScore}</div><div className="text-2xl md:text-3xl font-bold text-green-400">{bestScore}</div></div>
              <div className="bg-gray-900 p-4 md:p-6 rounded-2xl border border-gray-800 transition-colors"><div className="text-gray-500 text-[10px] md:text-xs uppercase tracking-wider mb-2">{text.totalWords}</div><div className="text-2xl md:text-3xl font-bold text-blue-400">{totalWordsSpoken.toLocaleString()}</div></div>
              <div className="bg-gray-900 p-4 md:p-6 rounded-2xl border border-gray-800 transition-colors"><div className="text-gray-500 text-[10px] md:text-xs uppercase tracking-wider mb-2">{text.topStrength}</div><div className="text-lg md:text-xl font-bold text-purple-400 truncate">{topStrength}</div></div>
              <div className="bg-gray-900 p-4 md:p-6 rounded-2xl border border-gray-800 transition-colors"><div className="text-gray-500 text-[10px] md:text-xs uppercase tracking-wider mb-2">{text.focusArea}</div><div className="text-lg md:text-xl font-bold text-pink-400 truncate">{focusArea}</div></div>
          </div>
      )}

      {history.length > 0 && (
          <div className="bg-gradient-to-r from-indigo-950 to-blue-950 border border-indigo-500/30 rounded-3xl overflow-hidden shadow-xl shadow-indigo-900/10">
              <div className="p-5 md:p-8 flex flex-col md:flex-row items-start md:items-center gap-6 cursor-pointer hover:bg-white/5 transition-colors group" onClick={() => setIsPlanExpanded(!isPlanExpanded)}>
                  <div className="relative flex-shrink-0">
                      <div className="bg-indigo-600 p-5 rounded-2xl shadow-lg shadow-indigo-500/30 group-hover:scale-110 transition-transform"><span className="text-3xl md:text-4xl">🎯</span></div>
                  </div>
                  <div className="flex-grow w-full">
                      <div className="flex flex-wrap items-center gap-3 mb-2">
                        <h3 className="text-lg md:text-2xl font-bold text-white uppercase tracking-tight">{text.actionPlan}</h3>
                        <span className="bg-indigo-500/20 text-indigo-300 text-[10px] md:text-xs px-2 py-1 rounded-md border border-indigo-500/30 font-mono">Focus: {weakestSkill.name}</span>
                        <span className="bg-blue-500/20 text-blue-300 text-[10px] md:text-xs px-2 py-1 rounded-md border border-blue-500/30 font-mono">{currentTierName}</span>
                      </div>
                      <p className="text-sm md:text-lg text-indigo-100/90 leading-relaxed font-serif">{suggestionObject.title}</p>
                      <div className="flex items-center gap-4 mt-4">
                          <div className="text-[10px] md:text-xs text-indigo-400 flex items-center gap-1.5 bg-black/30 px-3 py-1.5 rounded-full border border-indigo-500/10">
                              <svg className="w-3 h-3" fill="currentColor" viewBox="0 0 20 20"><path d="M10 18a8 8 0 100-16 8 8 0 000 16zm1-12a1 1 0 10-2 0v4a1 1 0 00.293.707l2.828 2.829a1 1 0 101.415-1.415L11 9.586V6z"></path></svg>
                              {nextMilestone} {text.pointsToRefresh}
                          </div>
                          <span className={`text-indigo-400 transform transition-transform duration-300 ml-auto ${isPlanExpanded ? 'rotate-180' : ''}`}>▼</span>
                      </div>
                  </div>
              </div>

              <div className={`overflow-hidden transition-all duration-500 ease-in-out ${isPlanExpanded ? 'max-h-[1000px] opacity-100' : 'max-h-0 opacity-0'}`}>
                   <div className="p-5 md:p-8 pt-0 border-t border-indigo-500/20 bg-black/20">
                        <div className="grid md:grid-cols-2 gap-8 mt-6">
                            <div>
                                <h4 className="text-indigo-300 font-bold text-xs uppercase tracking-widest mb-4">{text.goal}</h4>
                                <p className="text-gray-200 text-lg leading-snug font-serif bg-indigo-900/10 p-4 rounded-xl border border-indigo-500/10 mb-6">{suggestionObject.goal}</p>
                                {isAllCompleted && <p className="text-green-400 text-sm italic animate-fade-in">{text.congratsTasks}</p>}
                            </div>
                            <div>
                                <h4 className="text-indigo-300 font-bold text-xs uppercase tracking-widest mb-4">{text.tasks}</h4>
                                <ul className="space-y-4">
                                    {suggestionObject.tasks.map((task: string, idx: number) => {
                                        const isDone = !!completedTasks[`${planId}_${idx}`];
                                        return (
                                            <li key={idx} onClick={() => toggleTask(idx)} className={`flex items-start gap-4 p-3 rounded-xl cursor-pointer border transition-all ${isDone ? 'bg-green-900/20 border-green-500/30 opacity-60' : 'bg-white/5 border-white/5 hover:border-indigo-500/30'}`}>
                                                <span className={`flex-shrink-0 w-6 h-6 rounded-full flex items-center justify-center text-xs font-bold ${isDone ? 'bg-green-500 text-black' : 'bg-indigo-500/20 text-indigo-400'}`}>
                                                    {isDone ? '✓' : idx + 1}
                                                </span>
                                                <span className={`text-sm md:text-base ${isDone ? 'text-gray-400 line-through' : 'text-gray-200'}`}>{task}</span>
                                            </li>
                                        );
                                    })}
                                </ul>
                            </div>
                        </div>
                   </div>
              </div>
          </div>
      )}

      {history.length > 1 && (
